B.Sd=new A.dO("wbc","White Blood Cells","WBC","\xd710\xb3/\xb5L","CBC",4.5,11,3,null,2,null,!1,"Infection-fighting cells. Low WBC (neutropenia) means high infection risk during chemo nadir.")
B.S8=new A.dO("anc","Abs. Neutrophil Count","ANC","\xd710\xb3/\xb5L","CBC",1.5,8,1,null,0.5,null,!1,"Most critical infection-risk marker. ANC <0.5 = severe neutropenia. Report fever \u226538\xb0C immediately.")
B.Sb=new A.dO("rbc","Red Blood Cells","RBC","\xd710\u2076/\xb5L","CBC",3.8,5.2,3.2,null,2.5,null,!1,"Oxygen carriers. Low RBC = anemia \u2192 fatigue, breathlessness.")
B.Sk=new A.dO("hemoglobin","Hemoglobin","Hgb","g/dL","CBC",12,17.5,10,null,8,null,!1,"Hemoglobin carries oxygen. Levels <10 g/dL may require intervention. Monitor fatigue closely.")
B.Sj=new A.dO("platelets","Platelets","PLT","\xd710\xb3/\xb5L","CBC",150,400,75,null,50,null,!1,"Clotting cells. Low platelets = bleeding risk. Avoid NSAIDs. Report unusual bruising.")
